// ============================================================
// ✏️  EDIT YOUR SEARCH SETTINGS HERE
// ============================================================

const SEARCHES = [
  { keyword: 'dentists',            location: 'Los Angeles California' },
  // ADD MORE SEARCHES BELOW — just copy the line above
  // { keyword: 'plumbers',         location: 'Los Angeles California' },
  // { keyword: 'HVAC',             location: 'Houston Texas' },
  // { keyword: 'roofing',          location: 'Dallas Texas' },
  // { keyword: 'electricians',     location: 'New York City' },
  // { keyword: 'lawyers',          location: 'Chicago Illinois' },
  // { keyword: 'real estate',      location: 'Miami Florida' },
  // { keyword: 'auto repair',      location: 'Phoenix Arizona' },
  // { keyword: 'dentists',         location: 'San Francisco California' },
  // { keyword: 'plumbers',         location: 'San Diego California' },
];

// ============================================================
// YOUR API KEY — paste it here
const SERPAPI_KEY = 'PASTE_YOUR_SERPAPI_KEY_HERE';
// ============================================================

return SEARCHES.map(s => ({
  json: {
    keyword:    s.keyword,
    location:   s.location,
    api_key:    SERPAPI_KEY,
    query:      s.keyword + ' in ' + s.location
  }
}));

// Extract and clean each business from SerpAPI results
const input = $input.first().json;
const results = input.local_results || [];

if (results.length === 0) {
  console.log('No results found');
  return [];
}

return results.map(place => ({
  json: {
    name:            place.title                               || '',
    phone:           place.phone                               || '',
    website:         place.website                             || '',
    address:         place.address                             || '',
    city:            (place.address||'').split(',').slice(-3,-2)[0]?.trim() || '',
    state:           (place.address||'').split(',').slice(-2,-1)[0]?.replace(/\d+/g,'').trim() || '',
    rating:          place.rating   ? String(place.rating)    : '',
    reviews:         place.reviews  ? String(place.reviews)   : '',
    type:            place.type                                || '',
    google_maps_url: place.place_id ? 'https://www.google.com/maps/place/?q=place_id:' + place.place_id : '',
    hours:           place.hours                               || '',
    owner_name:      '',
    owner_email:     '',
    scraped_date:    new Date().toISOString().split('T')[0]
  }
}));

// Remove duplicate businesses
const seen = new Set();
const unique = [];

for (const item of $input.all()) {
  const key = (item.json.name + '|' + item.json.phone).toLowerCase().trim();
  if (!seen.has(key) && item.json.name) {
    seen.add(key);
    unique.push(item);
  }
}

console.log('Deduped: ' + $input.all().length + ' -> ' + unique.length);
return unique;

// Only keep businesses with phone OR website
const filtered = $input.all().filter(item => item.json.phone || item.json.website);
console.log('Kept ' + filtered.length + ' with contact info');
return filtered;

const count = $input.all().length;
const msg = '✅ Done! Added ' + count + ' leads to Google Sheets at ' + new Date().toISOString();
console.log(msg);
return [{ json: { status: 'success', leads_added: count, timestamp: new Date().toISOString() } }];
